# -*- coding: utf-8 -*-\nfrom rdflib import Graph\ng = Graph()\ng.parse('exports/rdf/medical_kg.ttl', format='turtle')\n\nqueries = {\n  'all_cases': 'PREFIX ex: <https://example.org/medical-multimodal-kg/> SELECT ?case ?dataset ?modality WHERE { ?case a ex:Case ; ex:dataset ?dataset ; ex:modality ?modality . } LIMIT 20',\n  'mentions': 'PREFIX ex: <https://example.org/medical-multimodal-kg/> SELECT ?text ?type WHERE { ?m a ex:Mention ; ex:text ?text ; ex:entity_type ?type . } LIMIT 20',\n  'audio_files': 'PREFIX ex: <https://example.org/medical-multimodal-kg/> SELECT ?file ?dataset ?duration WHERE { ?a a ex:AudioRecord ; ex:file_name ?file ; ex:dataset ?dataset . OPTIONAL { ?a ex:duration_sec ?duration . } } LIMIT 20',\n  'event_counts': 'PREFIX ex: <https://example.org/medical-multimodal-kg/> SELECT ?event_type (COUNT(?e) AS ?count) WHERE { ?e a ex:AudioEvent ; ex:event_type ?event_type . } GROUP BY ?event_type ORDER BY DESC(?count)',\n  'cross_modal': 'PREFIX ex: <https://example.org/medical-multimodal-kg/> SELECT ?mention_text ?audio_event_type WHERE { ?l a ex:MultimodalAlignment ; ex:linksMention ?m ; ex:linksAudioEvent ?e . ?m ex:text ?mention_text . ?e ex:event_type ?audio_event_type . } LIMIT 20'\n}\n\nfor name, q in queries.items():\n    print('\\n' + '='*90 + '\\n' + name + '\\n' + '='*90)\n    for row in g.query(q):\n        print(' | '.join(str(x) for x in row))\n